(window.courseContent = window.courseContent || {})["000003"] = {"files/Клинична Патология/Колоквиум 3 - Отделителна и Нервна система/1-msg-Теми по Нервна система.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Теми по Нервна система</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.8em;\n      margin-bottom: 0.15em;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0.1em; }\n    h4 { font-size: 1.05em; margin-bottom: 0.1em; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.2em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    p + ul, p + ol { margin-top: -0.5em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0.1em; \n    }\n    ul, ol { \n      margin: 0.5em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image styles are handled by inline styles and data-width attributes */\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n      line-height: 1 !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.3em; }\n      h2 { font-size: 1.1em; }\n      h3 { font-size: 1em; }\n      p { margin: 0.5em 0; }\n      ul, ol { padding-left: 1.2em; }\n      li { margin: 0.1em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 4px 6px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote>Version 1: поставени от AI без да са проверени. Информация само от учебника.</blockquote><h1 style=\"text-align: center\">138. Заболявания на нервната система: Мозъчен оток, повишено интракраниално налягане, вклиняване и хидроцефалия</h1><h2>Въведение в патологията на нервната система</h2><p>Патологичните процеси в нервната система се модифицират от специфични анатомо-физиологични особености, като най-съществената е разположението на мозъка в затворено черепно пространство. Други важни фактори са наличието на кръвно-мозъчна бариера (КМБ), липсата на лимфни пътища и наличието на специфична глиална тъкан.</p><hr><h2>Мозъчен оток</h2><p>Мозъчният оток представлява нарастване на водното съдържание в мозъчната тъкан, което води до увеличение на нейния обем.</p><h3>Етиология и морфогенеза</h3><p>Според патогенетичните механизми се различават три основни вида оток:</p><ul><li><strong>Вазогенен (екстрацелуларен):</strong> <p>Този вид оток се развива в междуклетъчното пространство. Основната причина за него е нарушената кръвно-мозъчна бариера. Най-често се наблюдава при състояния като артериална хипертония, тумори, абсцеси или интоксикация с олово. Поради увредената бариера, плазмените съставки преминават от кръвоносните съдове в мозъчната тъкан.</p></li><li><strong>Цитогенен (токсичен, интрацелуларен):</strong> <p>При него течността се натрупва вътре в самите клетки. Основният патогенетичен механизъм е нарушената работа на K/Na помпа. Това се случва най-вече при исхемия, водна интоксикация или състояния на остра хипонатриемия, което води до навлизане на вода в клетката и нейното набъбване.</p></li><li><strong>Интерстициален (перивентрикуларен):</strong> <p>Този оток е локализиран в тъканта около мозъчните стомахчета. Той е пряко свързан с наличието на <strong>хидроцефалия</strong>. Патогенезата тук включва нарушен транс-епендимен воден транспорт – поради повишеното налягане в стомахчетата, гръбначномозъчната течност се просмуква през епендимния слой (обвивката на стомахчетата) в околната мозъчна паренхима.</p></li></ul><p>Често механизмите са комбинирани поради едновременно нарушение на КМБ и водно-електролитното равновесие. Отокът може да бъде дифузен или перифокален (около огнищни процеси като хеморагии или тумори).</p><h3>Макроскопски характеристики</h3><p>При дифузен оток мозъкът е с увеличено тегло и обем, гънките са сплеснати, а браздите са силно стеснени. Срезната повърхност е овлажнена и блестяща, като границата между кората и бялото вещество е замъглена. Мозъчните вентрикули изглеждат цепковидни. В напреднали стадии може да се развие оточна некроза на бялото вещество. При цитогенния оток мозъкът може да е сух, състояние известно като мозъчно набъбване.</p><h3>Микроскопски характеристики</h3><p>Наблюдава се периваскуларно (във Вирхов-Робеновите пространства) и перицелуларно просветляване. При специфични състояния, като прионни енцефалити, се развива <em>status spongiosus</em>, при който в мозъка се виждат множество кухини, придаващи му вид на гъба.</p><p>В резултат на отока се увеличава мозъчния обем. При нарастването му над 8% от изходния (това е обемната разлика между мозъка и черепната вместимост) се развива СПВЧН. Поради това мозъчният оток обикновено се съпровожда с мозъчна дислокация и вклиняване.</p><hr><h2>Синдром на повишено вътречерепно налягане (СПВЧН)</h2><p>СПВЧН се дефинира като увеличение на ликворното налягане над 200 mm воден стълб или 15 mm живачен стълб. Патоморфологичен еквивалент на СПВЧН са мозъчните вклинявания или хернии.</p><h3>Етиология</h3><p>Синдромът се развива при всички патологични процеси, които водят до увеличаване на обема на черепното съдържание, включително обемни процеси като тумори, абсцеси, грануломи, хеморагии и др.</p><h3>Клинична картина</h3><p>Класическата клинична триада на СПВЧН включва:</p><ol><li>Силно главоболие.</li><li>Повръщане.</li><li>Застойни папили при офталмоскопия.</li></ol><h3>Макроскопски</h3><p>Вклиняванията (хернииране) са патоморфологичният еквивалент на СПВЧН и представляват пролабиране на част от мозъчната тъкан през естествени отвори на черепа или гънки на dura mater.</p><h4>Видове вклинявания</h4><ul><li><strong>Малкомозъчно вклиняване:</strong> Тонзилите на малкия мозък се вмъкват в големия тилен отвор (<em>foramen magnum</em>), притискайки продълговатия мозък. Това е честа причина за смърт поради увреждане на дихателния център, като могат да причинят и булбарна парализа.</li><li><strong>Темпорално (субтенториално) вклиняване:</strong> Долната темпорална гънка преминава през тенториума и притиска мезенцефалона и задната мозъчна артерия. <p>При него се уврежда контралатералното </p><p>мозъчно краче с развитие на парализа на III-ия ЧМН от същата страна, инфаркт в </p><p>мозъка при силна компресия на задна мозъчна артерия, руптура на пенетриращи артерии с вторични </p><p>стволови кръвоизливи (т.нар. кръвоизливи на </p><p>Duret).</p></li><li><strong>Субфалксово (цингуларно) вклиняване:</strong> Част от <em>gyrus cinguli</em> преминава под <em>falx cerebri</em> в срещуположната половина.</li><li><strong>Горно малкомозъчно вклиняване:</strong> <p>Част от вермиса и краниалната малкомозъчна </p><p>кора пролабират през тенториума в средна черепна ямка. Развива се при обемни процеси в малкия </p><p>мозък.</p></li></ul><h3>Усложнения</h3><p>Увеличеният мозъчен обем притиска вените и/или ликворните пътища, предизвиква общомозъчна исхемия, която задълбочава мозъчния оток. Връзката между двата процеса е много тясна и двупосочна. СПВЧН се причинява често от мозъчен оток и от своя страна утежнява развитието му.</p><hr><h2>Хидроцефалия</h2><p>Хидроцефалията е патологично разширение на ликворните пространства.</p><h3>Етиология и патогенеза</h3><p>Възниква поради блокаж на циркулацията или нарушен баланс между образуването и абсорбцията на цереброспиналната течност. Основните причини включват обтурация на ликворните пътища от тумори или възпаления, нарушена абсорбция или хиперпродукция на ликвор.</p><h3>Видове хидроцефалия</h3><ul><li><strong>Некомуникираща (обтурационна):</strong> Дължи се на запушване на пътищата (напр. <em>aquaeductus Sylvii</em> или отворите на Magendi и Luschka).&nbsp;<p>Конкретните причини за появата й най-често са мозъчни тумори на 3-ти и 4-ти вентрикул, </p><p>последвани по честота от хронично възпаление, </p><p>абсцеси, хеморагии на малкия мозък, грануломи, </p><p>паразити. </p><p>Обтурационната хидроцефалия е асиметрична </p><p>при запушване на foramen Monro.</p></li><li><strong>Комуникираща (необструктивна, абсорбционна):</strong> Свързана е с хиперпродукция (възпаление, папилом на хориоидния плексус) или нарушена абсорбция на ликвор в субарахноидното пространство (хронични менингити, субарахноидни кръвоизливи, тромбоза на венозните синуси).</li><li><strong>Хидроцефалия ex vacuo (пасивна):</strong>&nbsp;<p>Това е вид комуникираща хидроцефалия вследствие на атрофия на мозъка. Може да е вродена, </p><p>поради вътреутробни инфекции (токсоплазмоза, </p><p>цитомегалия) или свързана с малформации (поренцефалия, микрогирия, вродена стеноза на акведукта) и малформативни синдроми, каквито са с-м на </p><p>Dandy-Walker, с-м на Arnold-Chiari. Придобитата </p><p>хидроцефалия у възрастни е свързана с мозъчна </p><p>атрофия, породена от атеросклероза или дегенеративни заболявания.</p></li></ul><h3>Макроскопски характеристики</h3><p>Вентрикулната система е разширена симетрично или асиметрично. Бялото мозъчно вещество е атрофично, а <em>corpus callosum</em> е силно изтънял. При новородени състоянието води до увеличение на черепа и не затваряне на фонтанелите.</p><h3>Изход</h3><p>Увеличение на мозъчния обем, интерстициален оток и СПВЧН.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><h1 style=\"text-align: center\">139. Менингити и енцефалити: Видове и морфологична характеристика</h1><h1 style=\"text-align: center\">Менингити</h1><p>Менингитът представлява възпалителен процес на меките мозъчни обвивки, при който се наблюдава събиране на ексудат в субарахноидното пространство (САП). </p><h3>Етиология</h3><p>Причинителите са изключително разнообразни:</p><ul><li><strong>Вируси:</strong>&nbsp;</li><ul><li><strong>Първични вирусни менингити:</strong>&nbsp;<p>Ентеровируси (<i>ECHO-вируси</i>, <i>Coxsackie</i> вируси), както и вирусът на лимфоцитарния хориоменингит на Армстронг.</p></li><li><p><strong>Вторични вирусни менингити:</strong> </p><p>Вируси на грип, паротит (заушка), морбили, варицела, <i>Herpes-simplex</i>, <i>Epstein-Barr</i> вирус (инфекциозна мононуклеоза).</p><br></li></ul><li><strong>Бактерии:</strong>&nbsp;</li><ul><li><strong>Новородени:</strong> Най-чест причинител е <i>Escherichia coli</i>.</li><li><strong>Деца до 3 години:</strong> Основен причинител е <i>Haemophilus influenzae</i>.</li><li><strong>Деца и юноши</strong>: Най-характерен е <i>Neisseria meningitidis</i> (Менингокок).</li><li><strong>Възрастни:</strong> Преобладават пневмококи, стрептококи и стафилококи. Те често са вторични (след отит, синузит или пневмония).</li></ul></ul><ul><li><strong>Други:</strong> Туберкулозни микобактерии, луетична спирохета и гъбички (кандидоза, криптококоза).</li></ul><h3>Морфогенеза</h3><p>Микроорганизмите достигат до ЦНС по три основни пътя:</p><ol><li><strong>Кръвен ток (хематогенно):</strong> Най-честият път на разпространение.</li><li><strong>По съседство:</strong> От инфекции на костните синуси, средното ухо или мастоидния израстък.</li><li><strong>Директно:</strong> При черепно-мозъчни травми или медицински манипулации.</li></ol><h3>Клиника</h3><p>Менингитите се проявяват със следните основни синдроми:</p><ul><li><strong>Общ инфекциозен синдром</strong></li><li><strong>Синдром на менингеално дразнене</strong></li></ul><p>При <strong>хроничните менингити</strong> към клиничната картина се добавят:</p><ul><li><strong>Хидроцефален синдром</strong></li><li><strong>Увреждане на черепномозъчните нерви (ЧМН)</strong></li></ul><h3>Диагностика</h3><p>Най-съществените промени се установяват в <strong>ликвора</strong>. Те имат решаваща диагностична стойност за определяне на:</p><ol><li>Етиологията (причинителя)</li><li>Характера на възпалението</li></ol><h3>Видове според морфологичната характеристика</h3><p>Патоморфологичните промени зависят от вида на причинителя:</p><ul><li><strong>Серозни менингити (остри лимфоцитни):</strong> Предизвикват се предимно от вируси. Дифузни се и се&nbsp; характеризират с дифузен оток, хиперемия и инфилтрация от лимфоцити и макрофаги.</li><li><strong>Гнойни менингити:</strong> Причиняват се от гноеродни бактерии. Ексудатът е гноен и може да бъде разположен конвексиално (по повърхността) или базално.</li><li><strong>Грануломатозни менингити:</strong> Срещат се при туберкулоза (базален пихтиест ексудат и туберкули), луес (базални млечнобели менинги и луетични грануломи) или микози (базални съответни грануломи).</li><li><strong>Хроничен фиброзен базален менингит:</strong> Крайна фаза на неизлекувани менингити, протичаща с облитерация на САП и формиране на кисти. Етиологията е полиетиологична</li></ul><h2>Епидемичен цереброспинален менингит</h2><p>Това е остро инфекциозно заболяване, което се проявява със септична ангина и гнойно възпаление на менингите.</p><h3>Етиология</h3><p>Причинява се от <em>Neisseria meningitidis</em> (патогенни форми А и В). Заразяването става по въздушно-капков път от болни и заразоносители. Менингококите се развиват коменсално в устната кухина или причиняват лек назофарингит. Менингит възниква при изразена вирулентност и понижена имунна реактивност.</p><h3>Клиника:</h3><p>Известни са две клинико-морфологични форми - типична и свръхостра форма.</p><h3>Типична форма</h3><ul><li><strong>Макроскопски:</strong> През първите дни се наблюдава хиперемия и мътен ексудат, който бързо става гноен. Той обхваща менингите по конвекситета, формирайки характерната „гнойна шапка“. Мозъкът е силно оточен, а вентрикулите са изпълнени с гной.</li><li><strong>Микроскопски:</strong> Доминира обилна неутрофилна инфилтрация на менингите, съпроводена от макрофаги, лимфоцити и фибрин.</li></ul><h3></h3><h3>Типична форма</h3><ul><li><strong>Макроскопски:</strong></li><ul><li><p>През първия ден се установява</p><p>хиперемия и кръвоизливи с обилен мътен ексудат в </p><p>субарахноидното пространство</p></li><li><p>За 1-2 ден ексудатът става гноен</p>, образува „гнойна шапка“ по конвекситета и обхваща базалните менинги.</li><li>Мозъкът е силно оточен, а вентрикулите съдържат гной с жълтеникави налепи по епендима.</li></ul><li><strong>Микроскопски:</strong></li><ul><li>Преобладава масивна неутрофилна инфилтрация с макрофаги, лимфоцити и фибрин.</li><li>След 1-2 дни възпалението прониква и в мозъчната кора.</li><li><p>Менингококи могат да се докажат цитологично в ликвора.</p></li></ul><li><strong>Изход и усложнения:</strong></li><ul><li><p>Пълна резорбция на ексудата или оздравяване с фиброзиране на менингите.</p></li><li><p>Може да се </p><p>усложни с тежък мозъчен оток, със СПВЧН, с вклиняване, с разпространение на инфекцията </p>към мозъка.</li></ul></ul><h3>Свръхостра форма на менингококова инфекция (Менингококов сепсис, <span class=\"editor-note\" data-note=\"Бурното клинично развитие и патоморфологични промени са подобни на експерименталния генерализиран феномен на Санарели - Шварцман. /вж. Обща патология/\" id=\"note-1772905126248-0\">Синдром на Waterhouse-Friderichsen</span>)</h3><p>Може да възникне като усложнение на типичната форма или да се прояви още в началото с фулминантен (светкавичен) ход и смъртен изход за 24 часа, преди да се манифестира менингита.</p><ul><li><strong>Клиника:</strong></li><ul><li>Остро начало с висока температура и характерни хеморагични обриви по кожата.</li><li>Бързо преминаване в шоково състояние, което е резистентно на лечение.</li></ul><li><strong>Патогенеза:</strong></li><ul><li>Предизвиква се от менингококовия ендотоксин, отделящ се при разпадането на бактериите. </li><li><p>Ендотоксинемията причинява тежка </p><p>ендотелна увреда, активираща факторите на съсирването с последващо развитие на дисеминирана интравазална коагулация (ДИК).</p></li><li><p>Роля може да </p><p>има сензибилизацията на организма и потисната </p><p>имунна активност.</p><br></li><li>Възможна роля на дефицит в комплементната система (С6-С9).</li></ul><li><strong>Макроскопски:</strong></li><ul><li>Многобройни кръвоизливи по кожата, лигавиците и серозните обвивки.</li><li>Хеморагично-некротични промени във вътрешните органи.</li><li><p>Фибриноидна некроза и/или </p><p>фибринови тромби в съдовете на микроциркулацията - капиляри, артериоли, венули.</p><br></li><li><strong></strong><p>Типична находка </p><p>са <strong>двустранните масивни кръвоизливи в надбъбреците</strong>.</p></li><li><p>В менингите има оток, хиперемия и единични сегментоядрени левкоцити.</p></li></ul><li><strong>Изход:</strong></li><ul><li>Обикновено фатален, вследствие на рефрактерен септичен шок и остра надбъбречна недостатъчност.</li></ul></ul><h2>Пневмококови менингити</h2><p>Срещат се главно у възрастни вследствие на хематогенно пренасяне на инфекцията от вътрешни органи, най-често белите дробове. Ексудатът е богат на неутрофилни левкоцити и фибрин; в менингите се образуват плътни сраствания при организацията на ексудата.</p><h2>Стрептококови и стафилококови менингити</h2><p>Те са резултат от септикопиемия или разпространение на инфекцията от гноен синузит, отит, тромбофлебит на дурални венозни синуси. Усложненията са идентични на тези при епидемичния менингит, но има по-голяма възможност от образуване на мозъчен инфаркт или кръвоизлив, поради честото въвличане на съдовете във възпалителния процес.</p><h2>Грануломатозни менингити</h2><p>Те възникват при туберкулоза, луес, микотични инфекции (коксиоидоза, криптококоза, кандидоза, аспергилоза) и други.</p><h3>Клиника</h3><p>Характерни за клиничното протичанеса:</p><ul><li>Синдром на менингеално дразнене</li><li>Хидроцефално-хипертензионен синдром</li><li>Увреждане на ЧМН, поради базалната локализация на патологичния процес.</li><li>Образуване на мозъчни инфаркти при туберкулоза и особено при луес във връзка с облитериращия ендартерит.</li><li>Промени в ликвора, съответстващи на причинителя</li></ul><h3>Патоморфология. </h3><p>Носи белезите на съответните основни болестни процеси./вж. Инфекциозна патология/</p><h2>Хроничен обострен фиброзен базален менингит (базален кистичен арахноидит)</h2><p>Това е крайна фаза на неизлекувани менингити с различна етиология, фиброзирането на менингите причинява или пълна облитерация на субарахноидното пространство или частични сраствания с формиране на кисти.</p><hr><h1 style=\"text-align: center\"><hr>Енцефалити</h1><p>Енцефалитите са възпалителни процеси в мозъчното вещество, които се делят на:</p><ul><li><strong>Фокални некротично-гнойни:</strong> причинени от бактерии или микози.</li><li><strong>Дифузни алтернативно-възпалителни:</strong> причинени от вируси, рикетсии и неконвенционални агенти.</li></ul><h3></h3><h2><hr>Бактериални инфекции на мозъка</h2><p>Гнойното възпаление в мозъчното вещество протича под формата на мозъчен абсцес или разпространен емболичен гноен енцефалит (церебрит). Тези процеси могат да бъдат първични или да се развият като усложнение на гноен менингит.</p><h3>Мозъчен абсцес</h3><p>Огнищно гнойно-некротично възпаление, ограничено от глиална и фиброзна капсула. Причинява се най-често от стрептококи, пневмококи и стафилококи, произлизащи от гнойни огнища в белите дробове, ушите, синусите, мастоидния израстък, носа, кожата на лицето или при бактериален ендокардит. Клинично се характеризира с  със съчетание на СПВЧН с огнищна неврологична симптоматика. Възможно е да липсват прояви на инфекциозно заболяване. Ликворът е с повишено клетъчно и белтъчно съдържимо.</p><h4>Патоморфология</h4><ul><li><strong>Начален стадий:</strong> Локален пиогенен енцефалит (церебрит). Наблюдава се ограничена некроза с левкоцитна инфилтрация (гной) без демаркация. Тъканта е размекната, жълтеникава и с кръвоизливи.</li><li><strong>Стадий на формиране на пиогенна мембрана (14-21 ден):</strong> Гнойният ексудат се обгражда от капсула от гранулационна тъкан. Поради нарушена КМБ и пропускливи новообразувани съдове се развива тежък перифокален оток, водещ до асиметрично вклиняване.</li><li><strong>Стадий на фиброзиране на капсулата (2-3 месеца):</strong> Капсулата се състои от фибробластна и астроглиална тъкан (глиофиброза). Тя е по-плътна към менингите, докато пробивът на гнойта обикновено става във вентрикулната система през по-нежната част на капсулата.</li></ul><h4>Усложнения</h4><p>Pyocephalus internus (гной в мозъчните стомахчета), перифокален оток, вклиняване и пробив в субарахноидното пространство, водещ до менингит.</p><h3>Дифузен бактериален гноен енцефалит (церебрит)</h3><p>Развива се обикновено при септикопиемия.</p><ul><li><strong>Макроскопски:</strong> Не дава характерна картина, освен общи белези на мозъчен оток.</li><li><strong>Микроскопски:</strong> В кората и в бялото вещество се откриват множество периваскуларни инфилтрати, богати на левкоцити, със зони на микроабсцедиране и кръвоизливи.</li></ul><hr><h3></h3><h2>Остри вирусни енцефалити и миелити</h2><p>Тези възпалителни процеси се причиняват от вируси, които притежават специфичен тропизъм към нервната система или към нейни конкретни анатомични структури. В зависимост от локализацията и обема на засягане, заболяванията се класифицират на:</p><ul><li><strong>Полиоенцефалити:</strong> Патологичните промени са ограничени предимно в сивото мозъчно вещество (напр. бяс, остър полиомиелит).</li><li><strong>Паненцефалити:</strong> Възпалението обхваща в еднаква степен както сивото, така и бялото мозъчно вещество. Към тази група спадат редица заболявания, предавани чрез вектори като комари или кърлежи, които се характеризират и с специфично географско разпространение.</li></ul><h4>Етиология и патогенеза</h4><p>Голяма група от ДНК и РНК вируси проявяват невротропизъм към определени топографски структури. Вирусите проникват в ЦНС по няколко начина:</p><ul><li><strong>Хематогенно:</strong> Чрез виремия.</li><li><strong>Периневрално:</strong> Ретроградно по хода на лимфните пътища или чрез невроаксоналния ток.</li></ul><p>Когато възпалителният процес обхване целия спектър на нервната система, включително нервните коренчета и периферните нерви, състоянието се дефинира като енцефаломиелополирадикулоневрит.</p><h4>Морфологична картина</h4><p>Въпреки разликите в етиологията, вирусните енцефалити споделят сходна хистологична картина, различавайки се предимно по топографията на лезиите:</p><ul><li><strong>Макроскопски:</strong> Промените са неспецифични и включват оток и конгестия на мозъка и менингите. Съществуват изключения, като грипния енцефалит, който протича с изразени кръвоизливи, и Herpes-simplex енцефалитът, характеризиращ се с фокални некротични лезии.</li><li><strong>Микроскопски:</strong> Налице е характерна хистологична триада:</li><ol><li><strong>Клетъчна алтерация:</strong> Цитопатогенен ефект, водещ до клетъчен оток, хроматолиза и клетъчна смърт, което провокира невронофагия (фагоцитоза от микроглия и макрофаги).</li><li><strong>Мононуклеарни инфилтрати:</strong> Лимфоцити и макрофаги с типично периваскуларно разположение.</li><li><strong>Глиални възли (нодули):</strong> Резултат от огнищна пролиферация на глията.</li></ol></ul><p>Възпалението може да включва и специфични промени, дължащи се на директна вирусна репликация, като появата на ядрени или цитоплазмени инклузионни телца. \nСпоред класификацията на Coudry, вътреядрените включвания биват:</p><ul><li><p><strong>Тип А:</strong> Еозинофилни, единични, хомогенни, със светло хало.</p></li><li><strong>Тип В:</strong> По-малки от тип А, мултиплени, без наличие на хало.</li></ul><p>\nТопографията на лезиите е пряко свързана с вирусния тропизъм към определени клетки (неврони, глия) или конкретни области в централната нервна система. В зависимост от това дали се засяга предимно кората или бялото вещество, енцефалитите (и миелитите) се разделят на:</p><ul><li><strong>Полиоенцефалити (polio – сив):</strong> Възпалителните процеси са локализирани основно в сивото мозъчно вещество.</li><li><strong>Левкоенцефалити:</strong> Патологичните промени са ограничени в бялото мозъчно вещество.</li><li><strong>Паненцефалити:</strong> Характеризират се с дифузно засягане на мозъка, без селективна локализация в сивото или бялото вещество.</li></ul><h3></h3><h3>1. Остър преден полиомиелит (Poliomyelitis anterior acuta)</h3><p>Остро вирусно заболяване, засягащо предимно двигателните неврони в гръбначния мозък. Причинява се от полиовируси (семейство <em>Picornaviridae</em>, щам тип I „Брунхилда“ е най-патогенен), които са малки, без обвивка и с гол РНК геном.</p><h4>Патогенеза и разпространение</h4><p>Вирусът навлиза по ентерален път (фекално-орално). След първоначална репликация в лигавицата на храносмилателния тракт и назофаринкса, той навлиза в кръвообращението (виремия) и лимфната система. Оттам достига до ЦНС. Специфичният невротропизъм насочва репликацията към мотоневроните на предните рога на гръбначния мозък (особено в шийното и поясното задебеление), но може да засегне и двигателните ядра на мозъчния ствол, чак до гигантските пирамидни клетки на Бец в прецентралната мозъчна кора.</p><h4><strong></strong></h4><h4>Клиника:</h4><p>Клиничната картина се определя от локализацията на вирусната репликация в нервната система и етапът на възпалителния процес.</p><ol><li><strong>Спинална форма:</strong> Най-честата изява. Характеризира се с развитие на вяла пареза или парализа на долни или горни крайници вследствие на увреждането на мотоневроните в предните рога на гръбначния мозък.</li><li><strong>Булбарна, понтинна и енцефална форма:</strong> Тези варианти протичат значително по-тежко поради засягане на жизненоважни структури в мозъчния ствол, което води до съответна отпадна неврологична симптоматика.</li></ol><p>Заболяването преминава през четири фази, всяка от които има специфичен патоморфологичен израз:</p><ul><li><strong>Предпаралитичен стадий:</strong> Първоначална изява на вирусната инвазия и системната реакция, преди настъпването на трайни неврологични дефицити.</li><li><strong>Паралитичен (остър) стадий:</strong> В този период настъпват най-тежките морфологични промени: масивна некроза на мотоневроните, невронофагия, остра възпалителна инфилтрация (макрофаги, неутрофили и лимфоцити) и клетъчен оток.</li><li><strong>Възстановителен (подостър) стадий:</strong> Острата некроза преминава, възпалителната реакция започва да затихва, като се наблюдава устойчива лимфоцитна перивазална инфилтрация. </li><li><strong>Резидуален (хроничен) стадий:</strong> Финален етап, характеризиращ се с пълна загуба на неврони, заместване с немасивна глиофиброза и оформяне на псевдокисти. Клинично се установяват трайни парализи и мускулна атрофия от денервационен тип.</li></ul><h4>Морфологични стадии и промени</h4><ul><li><strong>Остра фаза:</strong></li><ul><li><strong>Макроскопски:</strong> Мозъкът и гръбнакът са силно хиперемирани и оточни. Напречните срези през гръбначния мозък показват „размита“ Н-образна структура на сивото вещество, мековата консистенция и множество точковидни кръвоизливи в областта на предните рога.</li><li><strong>Микроскопски:</strong> Тежки алтеративни промени в мотоневроните: хроматолиза (разпадане на нилсовото вещество), клетъчен оток и некроза. Засегнатите неврони се обграждат от микроглия и макрофаги, оформящи невронофагични възелчета. Установяват се също полиморфна възпалителна инфилтрация (неутрофили, лимфоцити) и еозинофилни инклузии (тип В по Coudry). Често се засягат и менингите.</li></ul><li><strong>Подостра фаза:</strong></li><ul><li><strong>Макроскопски:</strong> Областите на некроза придобиват сивкаво-ръждив цвят.</li><li><strong>Микроскопски:</strong> Възпалителният ексудат намалява, а преобладаващата картина става лимфоцитна перивазална инфилтрация, която може да персистира значително време.</li></ul><li><strong>Хронична фаза (Резидуална):</strong></li><ul><li><strong>Макроскопски:</strong> Предните рога на гръбначния мозък са отчетливо атрофични, бледи и осеяни с малки микрокисти (остатъци от некротични зони). Наблюдава се видима атрофия на предните коренчета.</li><li><strong>Микроскопски:</strong> Пълна загуба на мотоневрони, последвана от немасивна глиофиброза (заместване на нервната тъкан с глия). Мускулите, инервирани от тези сегменти, показват тежка денервационна атрофия.</li></ul></ul><h4>Клинични изходи</h4><p>Заболяването може да прогресира до респираторна недостатъчност (поради парализа на диафрагмата и междуребрените мускули) или възходяща парализа на Ландри. Булбарните форми са особено тежки, с висока смъртност (до 75%) поради парализа на жизненоважни центрове. При преживелите остават трайни парези, парализи и деформации, дължащи се на денервационната мускулна атрофия. Чести причини за късна смърт са вторични инфекции като пневмония и уросепсис.</p><h3>2. Полиомиелитоподобни енцефалити</h3><p>Заболявания, които клинично, епидемиологично и морфологично не се различават съществено от детския паралич. </p><ul><li><strong>Етиология:</strong> Предизвикват се от ентеровируси от групата <em>Picornaviridae</em> (ECHO, Coxsackie A и B, ентеровируси 70 и 71), а понякога и от <em>Herpes simplex</em>.</li><li><strong>Диагностика:</strong> Разграничаването от класическия полиомиелит се извършва единствено чрез лабораторна вирусна идентификация.</li><li><strong>Историческа справка:</strong> През 1975 г. в България е регистрирана голяма епидемия с висока смъртност, причинена от ентеровирус 71.</li></ul><h3>3. Бяс (Rabies)</h3><p>Остър, нелечим полиоенцефаломиелит, причинен от РНК вирус от семейство <em>Rhabdoviridae</em>.</p><ul><li><strong>Епидемиология и морфогенеза:</strong> Предава се чрез слюнка при ухапване от заразени животни (кучета, вълци, лисици, рядко прилепи). Вирусът се репродуцира в мускулите, достига до сензорните ганглии и се разпространява в ЦНС. Инкубационният период е 15-20 дни.</li><li><strong>Клиника:</strong> Започва с главоболие и температура, преминавайки в сетивна свръхвъзбудимост, хидрофобия, фотофобия и конвулсии.</li><li><strong>Микроскопска картина:</strong></li><ul><li><strong>Дегенеративни промени:</strong> Най-силно изразени в пода на IV вентрикул, стените на III вентрикул, мезенцефалона, базалните ганглии и хипокампа.</li><li><strong>Невронофагични възли:</strong> Описвани като „възелчета на бяса“.</li><li><strong>Патогномонични находки:</strong> <strong>Телца на Babes-Negri</strong> – цитоплазмени включвания (мултиплени, с еозинофилен център и базофилна периферия), разположени в невроните на хипокампа и клетките на Purkinje в малкия мозък.</li></ul><li><strong>Електронномикроскопски данни:</strong> Центърът на телцата на Negri съдържа вирусни протеини, заобиколени от нуклеокапсиди.</li><li><strong>Изход:</strong> Заболяването е фатално, като смъртта настъпва вследствие на булбарна парализа. Единствената ефективна мярка е профилактиката чрез противобясна ваксина.</li></ul><div><h3>4. Енцефалити от арборвируси</h3><p>Група трансмисивни енцефалити с подчертано географско разпространение, пренасяни от членестоноги.</p><ul><li><strong>Етиология:</strong> Вируси от семейство <em>Togaviridae </em>с изявен тропизъм към ЦНС.</li><li><strong>Епидемиология:</strong> Резервоар са гръбначни животни, а преносители — кърлежи и комари. В България и съседните страни спорадично се среща Далекоизточният руски енцефалит.</li><li><strong>Микроскопска картина:</strong> Картина на <strong>паненцефалит</strong>. Наблюдават се типични белези на вирусна инфекция: огнищни и изолирани невронални некрози, дегенерация и лимфоцитна инфилтрация. </li><ul><li>Липсва постоянна топографска характеристика, с изключение на Далекоизточния кърлежов енцефалит, където често се засягат мозъчният ствол и краниоспиналните пътища, което води до парези на раменния сплит.</li></ul><li><strong>Диагноза:</strong> Базира се на вирусологични изследвания, съобразени с епидемиологичната обстановка и специфичния географски ареал.</li></ul><h3></h3><h3>5. Herpes-simplex virus (HSV) енцефалит</h3><p>Това е латентна вирусна инфекция, която обикновено протича безсимптомно, но при определени условия може да предизвика тежък енцефалит. Различават се два основни варианта: <strong>HSV-I (лабиален)</strong> и <strong>HSV-II (генитален)</strong>.</p><h4>HSV-I енцефалит</h4><p>Засяга всички възрасти, като рискът е повишен при деца, младежи и имунокомпрометирани пациенти. При около 10% от заболелите се установява анамнеза за предшестващ лабиален херпес.</p><ul><li><strong>Макроскопска картина:</strong> Установяват се хеморагично-некротични промени с характерна локализация в темпоро-базалните и фронто-базалните части на мозъка. Понякога се засяга и мозъчният ствол.</li><li><strong>Микроскопска картина:</strong> Налице е дифузна, обилна полиморфно-клетъчна възпалителна инфилтрация. Диагностично специфични са <strong>интрануклеарните включвания тип А по Coudry</strong>, които се откриват в невроните и глиалните клетки.</li><li><strong>Диагностика:</strong></li><ul><li>Култивиране на вируса от ликвор (най-точен метод).</li><li>Доказване на вирусен антиген в мозъчна биопсия чрез имунопероксидазна техника.</li><li><em>In situ</em> хибридизация (високочувствителен метод).</li></ul><li><strong>Други прояви:</strong> HSV-I може да предизвика още серозен менигит, вакуолерна миелопатия (увреждане на латералните и дорзалните стълбове) или субакутен енцефалит със засягане на бялото мозъчно вещество.</li></ul><h4>HSV-II енцефалит</h4><p>Този вариант предизвиква паненцефалит, който морфологично наподобява HSV-I инфекцията, но се проявява предимно при новородени на фона на генерализирана вирусна инфекция.</p><div><hr><h3>Бавно развиващи се вирусни енцефалити</h3><p>Характеризират се с дълъг латентен период, бавен прогресиращ ход и липса на класическите клинични и епидемиологични белези на острите инфекциозни заболявания.</p><ul><li><strong>Основни представители:</strong></li><ul><li>Субакутен склерозиращ паненцефалит (ССПЕ).</li><li>Прогресивна мултифокална левкоенцефалопатия (ПМЛ).</li><li>Рубеолна енцефалопатия.</li></ul></ul><p><em>Забележка:</em> Прионните болести (спонгиоформени енцефалопатии), които доскоро се класифицираха тук, вече се разглеждат в раздела за дегенеративни заболявания на нервната система.</p><h4>Субакутен склерозиращ паненцефалит (ССПЕ)</h4><p>Исторически е известен с различни синоними: инклузионен енцефалит на Dawson, левкоенцефалит на Ludo van Bogaert или хиперкинетичен енцефалит. През 1972-1973 г. е доказано, че всички те имат един и същ причинител.</p><ul><li><strong>Етиология:</strong> Морбилозен РНК вирус (сем. <em>Paramyxoviridae</em>).</li><li><strong>Морфогенеза:</strong> Вирусът персистира в мозъка без активна репликация поради дефект на М-протеина (белтък от вътрешната обвивка, отговорен за сглобяването и отделянето на вирусните частици от клетката).</li><li><strong>Клинична картина:</strong> Проявява се с разнообразни хиперкинезии и дълбоки личностни промени.</li><li><strong>Макроскопска картина:</strong> Бялото мозъчно вещество е сиво-белезникаво, губи своя блясък и хомогенност.</li><li><strong>Микроскопска картина:</strong></li><ul><li>Полета на несистемна демиелинизация, некроза и псевдокисти в бялото вещество.</li><li>Наличие на нодуларна и дифузна глиоза.</li><li>Възпалителната реакция е слабо изразена (бедна), представена от перивазални мононуклеарни клетки.</li><li><strong>Диагностичен белег:</strong> В началните фази се откриват <strong>интрануклеарни включвания тип А по Coudry</strong> в невроните и глиалните клетки.</li></ul><li><strong>Диагноза:</strong> Поставя се чрез мозъчна биопсия, съчетана с имуноморфологично доказване на вирусни частици чрез специфични антитела.</li></ul><div><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"></div></div></div><br><h1><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><div style=\"text-align: center\">140. Трансмисивни и спонгиоморфни енцефалопатии - прионови заболявания</div></h1><h2>Определение и обща характеристика</h2><p>Прионовите болести, известни още като спонгиоформени енцефалопатии от неконвенционални агенти, представляват група заболявания, обединени от наличието на еднотипна спонгиоформена дегенерация на сивото мозъчно вещество. Дълго време те са причислявани към бавно-вирусните инфекции поради доказания им трансмисионен начин на предаване. Впоследствие обаче е установено натрупване на специфичен амилоид (PrPd), което ги сродява с дегенеративни заболявания като болестта на Алцхаймер.</p><hr><h2>Етиология и патогенеза</h2><p>Причинителите на тези заболявания са приони – протеинни инфекциозни частички с ниско молекулно тегло (27-30 kd), които не съдържат нуклеинови киселини (ДНК или РНК). Прионите се отличават с изключителна резистентност към стандартни методи на дезинфекция като формалин, ултравиолетови лъчи, радиация и висока температура.</p><p>Патогенезата включва превръщането на нормалния клетъчен прионов протеин (PrPc), който е разтворим, в патологична форма (PrPd) с бета-конфигурация. Този патологичен протеин полимеризира в амилоидни фибрили, наречени скрепи-асоциирани филаменти (S.A.F.). Трансмисионният характер на заболяванията е доказан чрез инокулиране на филтрат от мозък на болно животно в мозъка на здрави екземпляри, при които след дълъг латентен период (около 18 месеца) се развива идентична симптоматика.</p><hr><h2>Патоморфология</h2><h3>Макроскопски характеристики</h3><p>Макроскопските промени често са неспецифични. При болестта на Якоб-Кройцфелд може да се наблюдава мозъчна атрофия в крайните стадии. При Куру макроскопски промени обикновено не се откриват.</p><h3>Микроскопски характеристики</h3><p>Основният морфологичен белег е <strong>status spongiosus</strong> (гъбест вид). Той включва:</p><ul><li><strong>Тежка вакуолизация:</strong> Сливане на цитоплазмени вакуоли в невропила и невроните на сивото мозъчно вещество, което придава порьозен, микрокистичен вид на тъканта.</li><li><strong>Алтерация на невроните:</strong> Наблюдава се силна редукция до пълна загуба на неврони.</li><li><strong>Глиоза:</strong> Астроглиална пролиферация, съпътстваща невроналната загуба.</li><li><strong>Липса на възпаление:</strong> Характерно за прионовите болести е пълното отсъствие на възпалителна реакция.</li><li><strong>Амилоидни плаки:</strong> В някои случаи (особено при Куру) се откриват специфични плаки с амилоидно ядро.</li></ul><hr><h2>Клинични форми при хората</h2><h3>Болест на Jacob-Creutzfeldt (Якоб-Кройцфелд)</h3><p>Това е най-честата прионова болест при хората, наричана още трансмисивна деменция.</p><ul><li><strong>Честота:</strong> Развива се спорадично, най-често при мъже в петото десетилетие от живота.</li><li><strong>Клинична картина:</strong> Проявява се с прогресираща деменция и тежки неврологични нарушения.</li><li><strong>Морфология:</strong> Характеризира се с дифузен <em>status spongiosus</em> в кората на главния мозък.</li></ul><h3>Куру</h3><p>Заболяване, локализирано сред племето Форе в Нова Гвинея.</p><ul><li><strong>Етиология:</strong> Свързва се с ритуален канибализъм (консумация на мозъци на починали родственици), практикуван предимно от жени и деца.</li><li><strong>Клинична картина:</strong> Протича с церебеларна атаксия и тремор, прогресиращи до пълно обездвижване.</li><li><strong>Морфология:</strong> Наличие на характерни „плаки куру“ – струпвания от амилоиден протеин в сивото вещество.</li></ul><h3>Други форми</h3><p>Към прионовите заболявания при хората се причислява и синдромът на Gerstmann-Straussler.</p><hr><h2>Прионови болести при животните</h2><ul><li><strong>Скрепи (Scrapie):</strong> Заболяване по овцете и козите, което служи за прототип при изучаването на прионовите инфекции.</li><li><strong>Спонгиоформена енцефалопатия по говедата:</strong> Популярна като болест „луда крава“.</li><li><strong>Трансмисивна енцефалопатия по норки.</strong></li></ul><hr><h2>Диагноза</h2><p>Диагностиката на прионовите заболявания се базира на:</p><ol><li><strong>Микроскопско изследване:</strong> Установяване на характерния <em>status spongiosus</em>.</li><li><strong>Електронна микроскопия:</strong> Визуализиране на огромни мембранно ограничени вакуоли в невроните и откриване на скрепи-асоциирани филаменти (S.A.F.).</li><li><strong>Имуноморфология:</strong> Използване на специфични антисеруми срещу антиприонов протеин за идентифициране на патологичните изоформи в мозъчната тъкан.</li></ol><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><br><h1 style=\"text-align: center\"><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\">141. Демиелинизиращи заболявания. Мултиплена склероза</h1><h2>Обща характеристика</h2><p>Демиелинизиращите заболявания са група патологични състояния, обединени от водещия процес на демиелинизация (разрушаване на миелиновите обвивки при запазени аксони). Те обикновено са свързани с имунно-медирана патогенеза и възникват вследствие на инфекциозни или други неуточнени етиологични фактори. Типичен и най-често срещан представител на тази група е мултиплената склероза.</p><hr><h2>Мултиплена склероза (МС)</h2><p>Мултиплената склероза е хронично неврологично заболяване с рецидивиращ и прогресиращ ход, чиято основна морфологична характеристика е наличието на широко разпространени демиелинизационни огнища, известни като глиосклеротични плаки.</p><h3>Етиология</h3><p>Етиологията на заболяването не е напълно изяснена. Обсъждат се няколко основни теории:</p><ul><li><strong>Вирусна етиология:</strong> Предполага се ролята на вируса на кучешката чума (близък до морбилозния).</li><li><strong>Екологични фактори:</strong> Влияние на географската ширина (по-често в умерените пояси), режим на хранене и интоксикация с тежки метали.</li><li><strong>Генетична предразположеност:</strong> Установена е асоциация с определени HLA антигени (A3, B7, DW2, DRW2).</li></ul><h3>Патогенеза</h3><p>Патогенезата е имунно-медирана и включва взаимодействие между генетични фактори и външната среда. Наблюдава се дисбаланс в клетъчно-медирания имунитет с инхибиране на Т-супресорите (Tc) и активиране на Т-хелперите (Tx) по време на криза. Морфологичен субстрат на имунния процес е масивната Т-лимфоцитна инфилтрация в плаките. Специфична находка е рязкото увеличение на ликворните имуноглобулини (олигоклонални ивици), което се счита за вторичен феномен.</p><h3>Клинична картина</h3><p>Клиничните прояви са разнообразни и зависят от локализацията на плаките. Характерна е класическата <strong>триада на Charcot</strong>, която включва нистагъм, интенционен тремор и дизартия. Заболяването засяга предимно жени в активна възраст (между 20 и 40 години) и води до трайна инвалидизация.</p><h3>Макроскопски характеристики</h3><p>Патоморфологичната картина е патогномонична за диагнозата. Наблюдават се ясно ограничени плаки на демиелинизация с различна форма и големина.</p><ul><li><strong>Локализация:</strong> Плаките се разполагат в бялото вещество на главния мозък (често симетрично), мозъчния ствол, малкомозъчните крачета, гръбначния мозък и зрителните нерви. Характерна е перивентрикуларната локализация, особено в <strong>зоната на Steinert</strong> (ъгъла между <em>n. caudatus</em> и <em>corpus callosum</em>).</li><li><strong>Видове плаки:</strong> Свежите плаки са бледорозови и меки, докато хроничните са сивкави, рязко ограничени и с жилава (гумоподобна) консистенция.</li></ul><h3>Микроскопски характеристики</h3><ul><li><strong>Активни (свежи) плаки:</strong> Наблюдава се оток, демиелинизация и интензивен възпалителен процес с лимфоцитна инфилтрация. Установява се пролиферация на микроглия и макрофаги, които фагоцитират миелиновите фрагменти.</li><li><strong>Хронични (неактивни) плаки:</strong> Характеризират се с остър ръб, изразена глиофиброза (пролиферация на астроглия), наличие на хипертрофични астроцити и слаба възпалителна инфилтрация.</li><li><strong>Плаки-сенки:</strong> Зони на частична загуба на миелин, които постепенно преливат в нормалното бяло вещество.</li></ul><h3>Диагноза</h3><p>Диагнозата се подпомага от специфични оцветявания за миелин (MFB или луксол-фаст блу) и за аксони (сребърна импрегнация по Bodian). Имунохистохимично в центъра на плаките преобладават В-лимфоцити, а в периферията – Т-хелпери (Tx), чието увеличение корелира с прогресията на процеса.</p><hr><h2>Остър демиелинизиращ енцефаломиелит</h2><p>Това е полиетиологично възпалително заболяване, засягащо предимно бялото мозъчно вещество.</p><h3>Етиология и патогенеза</h3><p>Развива се като усложнение след общи инфекции (морбили, рубеола, заушка, варицела, Epstein-Barr вирус) или след ваксинации (например срещу бяс). Патогенезата е имунно-медирана, като възпалението се състои от клетки, участващи в имунния отговор.</p><h3>Морфология</h3><p>Микроскопски се установява дисеминиран възпалителен процес с перивенозна локализация на лимфо-плазмоцитни инфилтрати. Промените са най-силно изразени на границата между сивото и бялото мозъчно вещество. При тежки случаи може да се развие хеморагичен енцефалит с петехиални кръвоизливи.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><br><h1><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><div style=\"text-align: center\">142. Дегенеративни заболявания на централната нервна система. Болест на Алцхаймер</div></h1><h2>Обща характеристика и класификация</h2><p>Дегенеративните заболявания на нервната система са голяма група заболявания с голямо медицинско и социално значение. Основният им клиничен симптом е деменцията – прогресивно снижаване на интелектуалните способности на пациента. Съвременната класификация на тези състояния се базира на доказването на патологични протеини в мозъчната тъкан, като бета-амилоид (A4), тау-протеин, убиквитин, алфа-синуклеини и патологичен прионов протеин. Към тази група, освен болестта на Алцхаймер и Паркинсон, се причисляват деменцията с телца на Леви, болестта на Пик и прионовите болести.</p><hr><h2>Болест на Алцхаймер</h2><p>Болестта на Алцхаймер е най-честата форма на деменция, засягаща между 50% и 60% от дементните пациенти. Честотата ѝ нараства значително в развитите страни, което се обяснява с удължаването на продължителността на живота.</p><h3>Макроскопски характеристики</h3><p>Заболяването се характеризира със силно изразена мозъчна атрофия. Тя е най-силно подчертана в челните (фронтални) и париеталните дялове, както и в областта на хипокампа.</p><h3>Микроскопски характеристики</h3><p>Основните патоморфологични промени са два вида:</p><ul><li><strong>Невритни (сенилни) плаки:</strong> Представляват струпване на дегенерирали невритни израстъци, организирани около централно амилоидно ядро.</li><li><strong>Неврофибрилни възли (Алцхаймерова дегенерация):</strong> Това са задебелени, усукани и възловидни неврофибрили в клетъчните тела на невроните.</li></ul><p>Диагнозата се потвърждава чрез имунохистохимично изследване за тау-протеин и бета-амилоид. Стадирането на заболяването се определя от локализацията и гъстотата на неврофибрилните възли в различните отдели на мозъка.</p><hr><h2>Болест на Паркинсон (Идиопатичен паркинсонизъм)</h2><p>Това е дегенеративно заболяване, което засяга стрио-палидо-нигралната система. Клинично се проявява с класическа триада: дребен статичен тремор, брадикинезия (забавеност на движенията) и повишен мускулен тонус. Болестта трябва да се различава от паркинсоновия синдром, който може да бъде симптом на атеросклероза или интоксикации.</p><h3>Макроскопски характеристики</h3><p>Наблюдава се характерно избледняване на <em>substantia nigra</em> и на <em>locus coeruleus</em> в мезенцефалона.</p><h3>Микроскопски характеристики</h3><p>Установява се разрушаване на пигментираните неврони. Патогономичен белег за болестта са <strong>телцата на Леви</strong> – окръглени цитоплазмени включвания с по-бледа централна част и ясно очертана периферия. Те съдържат убиквитин и алфа-синуклеин.</p><hr><h2>Латерална амиотрофична склероза (ЛАС)</h2><p>ЛАС е системно дегенеративно заболяване на мотоневроните. Клинично протича с парализи, които прогресивно се засилват и водят до фатален край в рамките на 3 до 5 години.</p><h3>Етиология и патогенеза</h3><p>Етиологията не е напълно изяснена, като се предполага действието на токсични фактори. За разлика от други дегенеративни болести, тук не са доказани отлагания на специфични протеини.</p><h3>Морфологична характеристика</h3><p>Макроскопски промени обикновено не се долавят. Микроскопски се откриват тежки неспецифични дегенеративни изменения и некроза на мотоневроните от мозъчната кора до предните рога на гръбначния мозък. Наблюдава се загуба на неврони, минимална глиална реакция и пълна липса на възпаление.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><br><br><h1><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><div style=\"text-align: center\">143. Тумори на централната нервна система. Класификация</div></h1><h2>Обща характеристика на мозъчните тумори</h2><p>Туморната патология на централната нервна система (ЦНС) е изключително разнообразна, съответстваща на богатството от нормални клетъчни видове. В ЦНС се развиват тумори с невроепителен произход, тумори от мозъчните обвивки (менингеоми), както и тумори от мезенхимни, епителни или зародишни клетки. Метастатичните тумори също заемат значителен дял, като в последните години надхвърлят 30% от всички интракраниални неоплазми.</p><p>Специфична особеност на мозъчните тумори е несъответствието между тяхната хистологична степен на злокачественост и биологичното им поведение. Всички тумори в главния мозък, дори и хистологично „доброкачествените“, могат да предизвикат синдром на повишено вътречерепно налягане (СПВЧН) и да застрашат живота на пациента поради ограниченото черепно пространство. При най-честата група — глиомите — растежът е почти винаги инфилтративен, независимо от степента на диференциация.</p><hr><h2>Класификация на невроепителните тумори</h2><p>Това е най-голямата и специфична за ЦНС група тумори. Според класификацията на СЗО те се разделят на няколко основни вида:</p><ul><li><strong>Астроцитни тумори:</strong> Най-честите представители на глиомите.</li><li><strong>Олигодендроглиални тумори:</strong> Произхождат от олигодендроцитите.</li><li><strong>Епендимни тумори:</strong> Произхождат от епендимната глия.</li><li><strong>Тумори на хориоидния плексус:</strong> Водят началото си от епитела на плексуса.</li><li><strong>Ембрионални тумори:</strong> Характерни предимно за детската възраст (напр. медулобластом).</li><li><strong>Невронални, смесени и тумори в пинеалната област</strong>.</li></ul><hr><h2>Астроцитни тумори (Глиоми)</h2><p>Астроцитните тумори съставляват около 60% от всички глиоми. Те се класифицират в четири степени (I-IV) според нивото на анаплазия и инвазивност.</p><ul><li><strong>Дифузен астроцитом (II степен):</strong> Най-честият първичен невроепителен тумор при възрастни, локализиран предимно в бялото вещество. Макроскопски трудно се отличава от нормалната тъкан, а микроскопски е изграден от равномерно разпределени клетки с минимален атипизъм.</li><li><strong>Анапластичен астроцитом (III степен):</strong> Характеризира се с повишена клетъчна плътност, явен морфологичен атипизъм и поява на некротични огнища.</li></ul><hr><h2>Глиобластом (IV степен)</h2><p>Глиобластомът е най-малигненият първичен мозъчен тумор при възрастни. Той може да се развие първично (<em>de novo</em>) или вторично чрез дегенерация на по-нискостепенен астроцитом.</p><ul><li><strong>Макроскопски белези:</strong> Туморът има пъстра срезна повърхност поради честите некрози и хеморагии. Често се разпространява по миелиновите влакна на <em>corpus callosum</em> към другата хемисфера, приемайки характерната форма на „пеперуда“.</li><li><strong>Микроскопски белези:</strong> Характеризира се с триада от изразен клетъчен полиморфизъм, екстремна неоваскуларизация (съдовоендотелни пакети тип „гломерули“) и големи „географски“ некрози, заградени от псевдопалисади от туморни клетки.</li></ul><hr><h2>Други видове невроепителни тумори</h2><ul><li><strong>Олигодендроглиом (II-III степен):</strong> Микроскопски клетките му изглеждат еднакви, с кръгли ядра и светли ореоли („пчелна пита“), а стромата напомня „кафез за пилета“. Често съдържа калциеви отлагания.</li><li><strong>Епендимом (II степен):</strong> Свързан е със стените на вентрикулите. Микроскопски е патогномонично наличието на периваскуларни епендимни розети (<em>corona radiata</em>).</li><li><strong>Медулобластом:</strong> Най-честият ембрионален тумор при деца, локализиран във вермиса на малкия мозък. Микроскопски е изграден от малки „синьо-клетъчни“ структури, често формиращи розети на Hommer-Wright.</li></ul><hr><h2>Менингеални тумори (Менингеоми)</h2><p>Произлизат от клетките, покриващи мозъчните обвивки. Те са предимно доброкачествени и се срещат по-често при жени.</p><ul><li><strong>Макроскопски:</strong> Обикновено са сферични, плътни, сивкави възли, често здраво фиксирани към твърдата мозъчна обвивка (<em>dura mater</em>).</li><li><strong>Микроскопски:</strong> Най-характерният белег са менинготелните „луковици“ — концентрично подредени клетки около централен съд. Често се откриват и псамомни телца (калцирани структури).</li></ul><hr><h2>Метастатични тумори в ЦНС</h2><p>Могат да бъдат единични (солитарни) или множествени. Най-честите първични източници на метастази в мозъка са ракът на белия дроб, млечната жлеза, бъбреците, стомашно-чревния тракт и меланомът. В много случаи мозъчната симптоматика е първата клинична проява на скритото първично заболяване.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><h1 style=\"text-align: center\">144. Тумори на периферната нервна система</h1><h2>Обща характеристика</h2><p>Туморите на периферната нервна система произлизат основно от клетките на обвивките на нервите – Швановите клетки и клетките на периневриума. Към тази група се включват както доброкачествени образувания (невриноми), така и агресивни малигнени тумори. Специфична подгрупа са туморите на симпатиковата нервна система, които произлизат от клетките на невралния гребен и са характерни предимно за детската възраст.</p><hr><h2>Неврином (Неврилемом, Шваном)</h2><p>Невриномът е най-честият тумор в групата на периферните нерви и произхожда от Швановите клетки.</p><h3>Локализация</h3><p>Типичната локализация включва черепномозъчните нерви, като най-често се засяга <em>n. statoacusticus</em> в понтоцеребеларния ъгъл. Туморът може да се развие и в дорзалните коренчета на гръбначния мозък или по хода на периферните нерви.</p><h3>Макроскопски характеристики</h3><p>Макроскопски невриномите са добре капсулирани овоидни възли, здраво свързани с нерва, от който произхождат. Имат плътна консистенция и сиво-жълтеникав до ръждивокафяв цвят, което се дължи на стари кръвоизливи. Нерядко в структурата им се формират кисти.</p><h3>Микроскопски характеристики</h3><p>Хистологично се различават два типа полета:</p><ul><li><strong>Тип А (Antoni A):</strong> Снопчести участъци, изградени от източени клетки с палисадно подреждане на ядрата. Характерна структура са <strong>телцата на Верокай</strong>, представляващи две групи палисади, ограждащи безядрена зона.</li><li><strong>Тип В (Antoni B):</strong> Мрежовидни полета, съставени от звездовидни клетки със светла цитоплазма, в които често се наблюдават микрокисти и дегенеративни промени.</li></ul><p>Невриномите са доброкачествени тумори и не рецидивират след пълна хирургична екстирпация.</p><hr><h2>Малигнен тумор на обвивките на периферните нерви (MPNST)</h2><p>Този тумор се развива обикновено от големите нервни стволове и е анатомично свързан с тях.</p><h3>Морфогенеза и хистология</h3><p>Хистогенезата му е свързана с периневриума и Швановите клетки, които при туморна пролиферация придобиват способност да образуват колаген. Микроскопската му структура наподобява тази на фибросарком. Туморът се отличава с изключително агресивна еволюция и лоша прогноза.</p><hr><h2>Тумори на симпатиковата нервна система</h2><p>Произлизат от примордиалните клетки на невралния гребен, които формират симпатиковите ганглии и медулата на надбъбрека. В тази група се включват невробластом, ганглионевробластом и ганглионеврома.</p><hr><h2>Невробластом</h2><p>Невробластомът е четвъртият по честота злокачествен тумор при децата, като се среща изключително до 4-годишна възраст.</p><h3>Етиология и клиника</h3><p>Туморът се характеризира с бърз и агресивен растеж и ранно хематогенно метастазиране. Проявява секреторна активност с продукция на катехоламини, което се използва за диагностика.</p><h3>Локализация и макроскопия</h3><p>Най-честата локализация е в надбъбречната жлеза и ретроперитонеалното пространство (64%), следвани от задния медиастинум. Макроскопски туморът е мековат, розово-сивкав, без капсула и с множество кръвоизливи.</p><h3>Микроскопски варианти</h3><ul><li><strong>Недиференциран вариант:</strong> Изграден от малки „синьо-клетъчни“ структури, наподобяващи лимфоцити.</li><li><strong>Диференциран вариант:</strong> Наблюдават се белези на невронална диференциация и развитие на фибрилен матрикс. Характерно е формирането на <strong>розети тип Homer-Wright</strong>.</li><li><strong>Ганглионевробластом:</strong> Краен стадий на съзряване с наличие на зрели неврони и Шванови клетки.</li></ul><p>Прогнозата зависи от степента на хистологична диференциация и наличието на специфични онкопротеини като N-myc.</p><br><br>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\[', right: '\\]', display: true},\n    {left: '\\(', right: '\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>"};
